SET ANSI_NULLS ON; GO; SET QUOTED_IDENTIFIER ON; GO; SET NOCOUNT ON; SET XACT_ABORT ON;
/*
  Tabsan EduSphere — School Demo Data (Classes 1-10, Percentage Grading)
  ==================================================================
  1 Tenant x 1 Campus x 3 Depts x 15 Courses x 30 Students
  Grading: Percentage (A+ = 90%, A = 80%, B = 70%, C = 60%, D = 50%, F < 50%)
*/
IF DB_ID(N'Tabsan-EduSphere') IS NULL BEGIN RAISERROR('Run 01-Schema-Current.sql first.',16,1); RETURN; END;
GO
USE [Tabsan-EduSphere]; GO
DECLARE @Now DATETIME2=SYSUTCDATETIME(),@SAPwdHash NVARCHAR(512)=N'argon2id:kot3aIW+GTcmK4Ji/jGD7BxrNOEh57PLaFMUZrZa5oM=:v+XYusZ0Eu9Xs8Sz/7Hi58z4SrS9KsJ/ynnr/iCkkSk=',@PwdHash NVARCHAR(512)=N'argon2id:S7KBqFYDtoQ/+936WKnRGrfaizX10wKV9mIYdhbsO7M=:ncFDYnCu/jEm22iNzYCxdtkxnIZWWyRHRe7StVKmpvQ=';
DECLARE @RSA INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'SuperAdmin'),@RA INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Admin'),@RF INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Faculty'),@RS INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Student'),@RFn INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Finance');

/* ── TENANT & CAMPUS ── */
DECLARE @T UNIQUEIDENTIFIER=CAST('A0000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@C UNIQUEIDENTIFIER=CAST('B0000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER);
INSERT INTO [tenants] ([Id],[Code],[Name],[IsActive],[IsDeleted],[CreatedAt]) SELECT @T,N'SCH',N'School Tenant',1,0,@Now WHERE NOT EXISTS(SELECT 1 FROM [tenants] WHERE [Code]=N'SCH');
INSERT INTO [campuses] ([Id],[TenantId],[Code],[Name],[IsActive],[IsDeleted],[CreatedAt]) SELECT @C,@T,N'SCH-MAIN',N'School Campus',1,0,@Now WHERE NOT EXISTS(SELECT 1 FROM [campuses] WHERE [Code]=N'SCH-MAIN');

/* ── DEPARTMENTS ── */
DECLARE @P UNIQUEIDENTIFIER=CAST('C0000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@M UNIQUEIDENTIFIER=CAST('C0000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@S UNIQUEIDENTIFIER=CAST('C0000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER);
INSERT INTO [departments] ([Id],[Name],[Code],[InstitutionType],[TenantId],[CampusId],[IsActive],[IsDeleted],[CreatedAt]) SELECT d.Id,d.Name,d.Code,0,@T,@C,1,0,@Now FROM (VALUES (@P,N'Primary (Class 1-5)',N'PRI'),(@M,N'Middle (Class 6-8)',N'MID'),(@S,N'Secondary (Class 9-10)',N'SEC')) d(Id,Name,Code) WHERE NOT EXISTS(SELECT 1 FROM [departments] x WHERE x.[Id]=d.Id OR x.[Code]=d.Code);

/* ── PROGRAMS ── */
INSERT INTO [academic_programs] ([Id],[Name],[Code],[DepartmentId],[TotalSemesters],[MaxCreditLoadPerSemester],[IsActive],[IsDeleted],[CreatedAt]) SELECT p.Id,p.Name,p.Code,p.Did,p.S,p.C,1,0,@Now FROM (VALUES (CAST('D0000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),N'Primary Cert',N'PRI-CERT',@P,5,8),(CAST('D0000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),N'Middle Cert',N'MID-CERT',@M,3,8),(CAST('D0000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),N'Secondary Cert',N'SEC-CERT',@S,2,8)) p(Id,Name,Code,Did,S,C) WHERE NOT EXISTS(SELECT 1 FROM [academic_programs] x WHERE x.[Id]=p.Id);

/* ── SEMESTERS (Class 1-10) ── */
INSERT INTO [semesters] ([Id],[Name],[StartDate],[EndDate],[IsClosed],[IsDeleted],[CreatedAt]) SELECT s.Id,s.Name,s.StartDate,s.EndDate,1,0,@Now FROM (VALUES (CAST('E0000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),N'Class 1','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),N'Class 2','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),N'Class 3','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER),N'Class 4','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000005' AS UNIQUEIDENTIFIER),N'Class 5','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000006' AS UNIQUEIDENTIFIER),N'Class 6','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000007' AS UNIQUEIDENTIFIER),N'Class 7','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000008' AS UNIQUEIDENTIFIER),N'Class 8','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000009' AS UNIQUEIDENTIFIER),N'Class 9','2025-08-01','2026-05-31'),(CAST('E0000000-0000-0000-0000-000000000010' AS UNIQUEIDENTIFIER),N'Class 10','2025-08-01','2026-05-31')) s(Id,Name,StartDate,EndDate) WHERE NOT EXISTS(SELECT 1 FROM [semesters] x WHERE x.[Id]=s.Id);
DECLARE @C1 UNIQUEIDENTIFIER=CAST('E0000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@C5 UNIQUEIDENTIFIER=CAST('E0000000-0000-0000-0000-000000000005' AS UNIQUEIDENTIFIER),@C6 UNIQUEIDENTIFIER=CAST('E0000000-0000-0000-0000-000000000006' AS UNIQUEIDENTIFIER),@C8 UNIQUEIDENTIFIER=CAST('E0000000-0000-0000-0000-000000000008' AS UNIQUEIDENTIFIER),@C9 UNIQUEIDENTIFIER=CAST('E0000000-0000-0000-0000-000000000009' AS UNIQUEIDENTIFIER),@C10 UNIQUEIDENTIFIER=CAST('E0000000-0000-0000-0000-000000000010' AS UNIQUEIDENTIFIER);

/* ── COURSES (5 per dept = 15) ── */
DECLARE @Cr TABLE (Id UNIQUEIDENTIFIER,T NVARCHAR(200),Cd NVARCHAR(20),CrH INT,Did UNIQUEIDENTIFIER,CT INT,GT NVARCHAR(20));
INSERT INTO @Cr VALUES (CAST('F0000000-0000-0000-0000-000001001' AS UNIQUEIDENTIFIER),N'English (Primary)',N'PRI-ENG',4,@P,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000001002' AS UNIQUEIDENTIFIER),N'Mathematics Primary',N'PRI-MATH',4,@P,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000001003' AS UNIQUEIDENTIFIER),N'Science Primary',N'PRI-SCI',4,@P,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000001004' AS UNIQUEIDENTIFIER),N'Urdu Primary',N'PRI-URD',4,@P,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000001005' AS UNIQUEIDENTIFIER),N'General Knowledge',N'PRI-GK',3,@P,2,N'Percentage'),(CAST('F0000000-0000-0000-0000-000002001' AS UNIQUEIDENTIFIER),N'English Middle',N'MID-ENG',5,@M,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000002002' AS UNIQUEIDENTIFIER),N'Mathematics Middle',N'MID-MATH',5,@M,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000002003' AS UNIQUEIDENTIFIER),N'Science Middle',N'MID-SCI',5,@M,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000002004' AS UNIQUEIDENTIFIER),N'Computer Science',N'MID-CS',4,@M,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000002005' AS UNIQUEIDENTIFIER),N'History & Geography',N'MID-HG',4,@M,2,N'Percentage'),(CAST('F0000000-0000-0000-0000-000003001' AS UNIQUEIDENTIFIER),N'English Secondary',N'SEC-ENG',5,@S,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000003002' AS UNIQUEIDENTIFIER),N'Mathematics Secondary',N'SEC-MATH',5,@S,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000003003' AS UNIQUEIDENTIFIER),N'Physics',N'SEC-PHY',5,@S,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000003004' AS UNIQUEIDENTIFIER),N'Chemistry',N'SEC-CHEM',5,@S,1,N'Percentage'),(CAST('F0000000-0000-0000-0000-000003005' AS UNIQUEIDENTIFIER),N'Biology',N'SEC-BIO',5,@S,1,N'Percentage');
INSERT INTO [courses] ([Id],[Title],[Code],[CreditHours],[DepartmentId],[CourseType],[GradingType],[HasSemesters],[IsActive],[IsDeleted],[CreatedAt]) SELECT c.Id,c.T,c.Cd,c.CrH,c.Did,c.CT,c.GT,1,1,0,@Now FROM @Cr c WHERE NOT EXISTS(SELECT 1 FROM [courses] x WHERE x.[Id]=c.Id);

/* ── USERS ── */
DECLARE @SA UNIQUEIDENTIFIER=CAST('70000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@AP UNIQUEIDENTIFIER=CAST('7000000A-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@AM UNIQUEIDENTIFIER=CAST('7000000A-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@AS UNIQUEIDENTIFIER=CAST('7000000A-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),@FN UNIQUEIDENTIFIER=CAST('7000000A-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER);
